import sys
syms = []
for line in sys.stdin:
    parts = line.split()
    if len(parts) >= 8 and parts[3] == 'FUNC':
        try:
            addr = int(parts[1], 16)
            size = int(parts[2])
            name = parts[7]
            if addr > 0 and size > 0:
                syms.append((addr, size, name))
        except:
            pass

for target_addr in [0x2f4b20, 0x2f4c84, 0x222098, 0x2241ac, 0x1abc80, 0x16de04, 0x2c1a40]:
    found = False
    for addr, size, name in syms:
        if addr <= target_addr < addr + size:
            offset = target_addr - addr
            print(f'0x{target_addr:x} -> {name}+0x{offset:x} (func 0x{addr:x}, size {size})')
            found = True
            break
    if not found:
        # Find nearest function before
        best = None
        for addr, size, name in sorted(syms):
            if addr <= target_addr:
                best = (addr, size, name)
            else:
                break
        if best:
            print(f'0x{target_addr:x} -> {best[2]}+0x{target_addr - best[0]:x} (nearest func, may be outside bounds)')
        else:
            print(f'0x{target_addr:x} -> NOT FOUND')
"

