# Check which section these addresses fall in
readelf -S libmonosgen-2.0.so 2>/dev/null | python3 -c "
import sys
sections = []
for line in sys.stdin:
    line = line.strip()
    if ']' in line and ('PROGBITS' in line or 'NOBITS' in line):
        parts = line.split()
        for i, p in enumerate(parts):
            if p in ('PROGBITS', 'NOBITS'):
                # name is before, addr is two before type
                name = parts[i-3] if i >= 3 else '?'
                try:
                    addr = int(parts[i-2], 16)
                    offset = int(parts[i-1], 16)
                    size = int(parts[i+1], 16)
                    sections.append((name, addr, size, offset))
                except:
                    pass
                break

for target in [0x2f4b20, 0x2f4c84]:
    for name, addr, size, offset in sections:
        if addr <= target < addr + size:
            print(f'0x{target:x} is in section {name} (0x{addr:x}-0x{addr+size:x})')
            break
    else:
        print(f'0x{target:x} not found in any section')
"
